use std::io::Write;
use std::path::PathBuf;

use craft_schema::typescript_sdk_types;

const HEADER: &str = "//
// AUTO-GENERATED by craft-schema -- do not edit by hand.
// Regenerate with: cargo run -p craft-schema --bin gen-sdk
//
";

fn main() -> std::io::Result<()> {
    let args: Vec<String> = std::env::args().collect();
    let out = args
        .get(1)
        .cloned()
        .unwrap_or_else(|| "sdk/src/generated.ts".to_string());
    let path = PathBuf::from(&out);
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent)?;
    }
    let mut f = std::fs::File::create(&path)?;
    f.write_all(HEADER.as_bytes())?;
    f.write_all(typescript_sdk_types().as_bytes())?;
    println!("wrote {}", out);
    Ok(())
}
